using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // EF 9 breaking change #1: Discriminator property renamed to "$type".
            // Existing documents use "Discriminator", so preserve the old name.
            entity.HasDiscriminator<string>("Discriminator");

            // EF 9 breaking change #2: Id property now maps to "id" (the Cosmos system property)
            // instead of being auto-formatted as "EntityType|KeyValue".
            // Existing documents have id = "Blog|<key>", so keep the old format.
            entity.HasKey(b => b.Id);
            entity.Property(b => b.Id)
                  .ToJsonProperty("id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();

            // EF 9 breaking change #3: HasIndex() now throws for Cosmos (indexes are managed
            // by Cosmos indexing policy, not EF). Removed the HasIndex call.
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; }

}

